import { Challenge, PathType } from "@/types";

type RawChallenge = Omit<Challenge, "path">;

// Social Anxiety / Social Confidence Path - 60 Days
const socialAnxietyChallenges: RawChallenge[] = [
  { id: 1, day: 1, title: "Grounded Breathing", description: "Stand in a public place and take five deep, calm breaths. Notice how your body feels—no need to change anything. (~30s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Deep breathing activates your parasympathetic nervous system, physically lowering anxiety before social exposure." },
  { id: 2, day: 2, title: "Three-Second Glance", description: "Make eye contact with three different people. Hold each look for about three seconds. Keep your face neutral—no need to smile or nod. (~10–20s each)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Brief, neutral eye contact rewires your brain's threat-detection system — it learns that being seen is safe." },
  { id: 3, day: 3, title: "Neutral Greeting", description: "Say a brief 'hi' or 'good morning' to someone nearby. Use a plain, neutral tone and don't explain or justify it. (~5s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Initiating contact without over-explaining builds a new mental model: you don't need permission to speak." },
  { id: 4, day: 4, title: "Visible Waiting", description: "Sit or stand in a visible spot for two minutes without using your phone. Let yourself be seen—no performing required. (2m)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Sitting with the discomfort of visibility teaches your nervous system that attention isn't danger — it's just attention." },
  { id: 5, day: 5, title: "Clear Voice", description: "Ask one simple question to a stranger using a confident, clear voice. Keep it to one sentence. (~10–20s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Projecting your voice triggers a feedback loop: your brain hears confidence and starts believing it." },
  { id: 6, day: 6, title: "Deliberate Pause", description: "In a conversation today, pause for three seconds before replying. Resist the urge to fill the silence. (~3s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Intentional pauses signal self-assurance — rushing to reply is often a people-pleasing reflex, not a conversational necessity." },
  { id: 7, day: 7, title: "No Softeners", description: "Make one clear statement without words like 'just', 'maybe', or 'I think'. State it directly and stop. (~5–10s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Softening language is a protective habit; dropping it shows your brain that directness doesn't cause rejection." },
  { id: 8, day: 8, title: "Own Not Knowing", description: "If you don't know an answer, say 'I don't know' plainly—no apology, no explanation. (~5s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Admitting ignorance without shame dismantles the perfectionism that fuels social anxiety — nobody knows everything." },
  { id: 9, day: 9, title: "Request Clarity", description: "Ask someone to repeat themselves once, even if you mostly heard them. Practice a calm tone. (~5–10s)", difficulty: "easy", xpReward: 50, category: "foundation", proTip: "Asking for repetition normalizes your needs in conversation — you're teaching yourself that your understanding matters." },
  { id: 10, day: 10, title: "Sustained Volume", description: "Say one whole sentence at a steady, confident volume—like speaking across a small room. Keep the tone even. (~10–20s)", difficulty: "easy", xpReward: 150, category: "foundation", proTip: "Sustained volume builds vocal confidence — your voice deserves space, and claiming it physically reinforces emotional presence." },
  { id: 11, day: 11, title: "Store Presence", description: "Enter a shop and browse for two minutes without needing to buy anything. If approached, respond simply—no excuses required. (2m)", difficulty: "easy", xpReward: 60, category: "initiation", proTip: "Existing in public without a transactional purpose challenges the belief that you need a 'valid reason' to take up space." },
  { id: 12, day: 12, title: "Direct Request", description: "Ask a staff member where something is using seven words or fewer. Keep it practical and brief. (~10–20s)", difficulty: "easy", xpReward: 60, category: "initiation", proTip: "Ultra-brief requests prove that social interactions can be purely functional — no performance required." },
  { id: 13, day: 13, title: "Front Row Sitting", description: "Choose a visible seat (front of a café, middle of a waiting area) and sit there for five minutes without hiding. (5m)", difficulty: "easy", xpReward: 60, category: "initiation", proTip: "Choosing a visible spot voluntarily rewires the brain's safety-seeking behavior — you're not hiding, and nothing bad happens." },
  { id: 14, day: 14, title: "Weather Comment", description: "Make a short, neutral comment about the weather or surroundings to someone nearby. Keep it one sentence and end. (~5–10s)", difficulty: "medium", xpReward: 70, category: "initiation", proTip: "Low-stakes small talk is social glue — succeeding at it proves you can connect without needing to be interesting." },
  { id: 15, day: 15, title: "Simple Thanks", description: "Say 'thanks' or 'thank you' and stop—no extra phrases or over-emphasis. (~3–5s)", difficulty: "medium", xpReward: 60, category: "initiation", proTip: "A clean, unadorned 'thank you' is more powerful than an over-explained one — brevity reads as confidence." },
  { id: 16, day: 16, title: "Second Question", description: "Ask a stranger one question. After they answer, follow with one short follow-up. Keep both short. (~30s)", difficulty: "medium", xpReward: 70, category: "initiation", proTip: "Following up shows genuine curiosity — it shifts your focus from 'how do I look?' to 'what can I learn about this person?'" },
  { id: 17, day: 17, title: "Smile & Drop", description: "Make brief eye contact, smile for a second, then return to a neutral expression. Don't hold it. (~3–5s)", difficulty: "medium", xpReward: 60, category: "initiation", proTip: "A brief smile and release demonstrates that warmth doesn't require follow-through — you can connect and move on." },
  { id: 18, day: 18, title: "Boring Statement", description: "Say a factual, unexciting sentence (e.g., 'It's crowded today'). Don't add color or excuses. (~5–10s)", difficulty: "medium", xpReward: 60, category: "initiation", proTip: "Speaking without entertaining proves you're allowed to exist without performing — not every utterance needs sparkle." },
  { id: 19, day: 19, title: "Simple Compliment", description: "Offer one brief, specific compliment. One sentence—then end the interaction. (~10–15s)", difficulty: "medium", xpReward: 70, category: "initiation", proTip: "Giving a compliment shifts your brain from self-monitoring to other-focused attention — the antidote to social anxiety." },
  { id: 20, day: 20, title: "Incomplete Exit", description: "Exit a conversation mid-flow: say 'I need to go' and leave. Don't over-finish the interaction. (~5–10s)", difficulty: "medium", xpReward: 150, category: "initiation", proTip: "Leaving without a polished exit teaches your brain that you control when interactions end — you don't need permission to leave." },
  { id: 21, day: 21, title: "Cashier Exchange", description: "Have a short (about 30s) exchange with a cashier—ask about their day or comment briefly. Keep it natural. (30s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Low-risk exchanges with service workers are practice reps for real conversations — each one builds neural pathways for social ease." },
  { id: 22, day: 22, title: "Open-Ended Question", description: "Ask someone a question that requires more than yes/no. Then listen to their full answer without planning your response. (~1–2m)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Listening without rehearsing your reply is the core of genuine connection — it quiets the inner critic." },
  { id: 23, day: 23, title: "Mild Opinion", description: "Share a small, neutral opinion (about coffee, a show, the weather). State it as fact—no over-apology. (~20–40s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Stating opinions as facts retrains the belief that your perspective is inherently invalid or needs softening." },
  { id: 24, day: 24, title: "Unscripted Response", description: "Respond to three questions in conversation without planning your words ahead. Keep answers short and honest. (~1–2m)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Over-planning responses is a control strategy; speaking unscripted proves you're capable without the safety net." },
  { id: 25, day: 25, title: "Admit Confusion", description: "Tell someone 'I don't understand' and ask them to explain differently. Keep it simple. (~10–30s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Admitting confusion is a strength — it models intellectual honesty and relieves the pressure to appear competent at all times." },
  { id: 26, day: 26, title: "Five-Second Silence", description: "Allow five seconds of silence in a conversation. Don't rush to fill it—then continue naturally. (~5s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Silence in conversation is normal — tolerating it dismantles the anxious belief that you're responsible for keeping things flowing." },
  { id: 27, day: 27, title: "Ask for Assistance", description: "Ask someone for small help (directions, a pen, brief advice). Accept whatever they offer. (~30s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Asking for help challenges the core belief that you're a burden — most people actually enjoy being useful." },
  { id: 28, day: 28, title: "Full Sentence Answer", description: "Answer a yes/no question with a full sentence that gives brief context, then stop. (~10–20s)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Expanding beyond yes/no asserts that your thoughts deserve airtime — you're not just a respondent, you're a participant." },
  { id: 29, day: 29, title: "Day Recap", description: "When asked how your day went, tell an actual 60-second story—one clear event, one minute, no embellishment. (1m)", difficulty: "medium", xpReward: 80, category: "authenticity", proTip: "Sharing real experiences (not polished summaries) deepens relationships — authenticity invites others to be real too." },
  { id: 30, day: 30, title: "Neutral Reception", description: "When someone reacts neutrally to you, resist fixing it or seeking approval—accept the neutral response. (~instant)", difficulty: "medium", xpReward: 150, category: "authenticity", proTip: "Neutral responses are not rejections — tolerating them breaks the habit of scanning faces for approval to calibrate your self-worth." },
  { id: 31, day: 31, title: "State Your Preference", description: "When asked, say your actual preference first. Do not defer—use one brief sentence. (~5–10s)", difficulty: "medium", xpReward: 90, category: "expression", proTip: "Stating preferences without deferring rewires the people-pleasing instinct — your desires are valid input, not impositions." },
  { id: 32, day: 32, title: "Gentle Disagreement", description: "Say 'I see it differently' or 'I disagree' and offer one short reason. Practice once silently first if needed. (~20–40s)", difficulty: "medium", xpReward: 80, category: "expression", proTip: "Disagreeing respectfully proves that conflict doesn't equal rejection — relationships can survive and even strengthen through difference." },
  { id: 33, day: 33, title: "Small Vulnerability", description: "Share a minor vulnerability (something small you're not great at) in one sentence. Keep boundaries in mind. (~10–20s)", difficulty: "hard", xpReward: 100, category: "expression", proTip: "Strategic vulnerability is a social superpower — it signals trust and invites reciprocal openness, the foundation of deeper connection." },
  { id: 34, day: 34, title: "Express Disinterest", description: "Politely say that something doesn't interest you—no apologies or over-justifying. (~10–20s)", difficulty: "medium", xpReward: 90, category: "expression", proTip: "Expressing disinterest without guilt reinforces that you're a separate person with your own tastes — not a mirror for others." },
  { id: 35, day: 35, title: "Unapologetic Dislike", description: "State a genuine dislike without qualifying it (avoid 'but some people like it'). Keep it short. (~10–20s)", difficulty: "medium", xpReward: 90, category: "expression", proTip: "Owning your dislikes without hedging signals self-trust — you don't need group consensus for your feelings to be valid." },
  { id: 36, day: 36, title: "Personal Share", description: "Share a mildly personal detail (hobby, weekend highlight, small goal). Keep it conversational and safe. (~30–60s)", difficulty: "medium", xpReward: 90, category: "expression", proTip: "Personal sharing builds relational depth — people bond over specifics, not generic pleasantries." },
  { id: 37, day: 37, title: "Name the Feeling", description: "Say 'I feel nervous' or 'I feel awkward' in the moment and keep speaking—don't stop. (~5–20s)", difficulty: "hard", xpReward: 100, category: "expression", proTip: "Naming the feeling in real-time disarms it — acknowledging anxiety publicly robs it of its secret power over you." },
  { id: 38, day: 38, title: "Receive Feedback Openly", description: "Ask one person what they think about a short comment you made. Listen fully and don't defend. (~1–2m)", difficulty: "hard", xpReward: 100, category: "expression", proTip: "Seeking feedback voluntarily transforms criticism from a threat into a tool — you're in control of the inquiry." },
  { id: 39, day: 39, title: "Rough-Draft Thinking", description: "Share a not-yet-polished thought and say it's a 'rough idea'—invite input or leave it. (~20–40s)", difficulty: "medium", xpReward: 90, category: "expression", proTip: "Sharing unfinished thoughts fights perfectionism — most great ideas start messy, and collaboration improves them." },
  { id: 40, day: 40, title: "Unfiltered Minute", description: "Talk for one minute about something you genuinely care about. Purposefully avoid editing yourself. (~1m)", difficulty: "hard", xpReward: 150, category: "expression", proTip: "Passion bypasses the inner editor — when you care about a topic, self-consciousness fades and authentic presence emerges." },
  { id: 41, day: 41, title: "Hidden Truth", description: "Share a small truth you'd usually hide (within safe boundaries). Prep: choose a low-risk recipient. (~30–60s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Selective honesty with safe people builds the muscle for authentic living — secrecy is exhausting; openness is freeing." },
  { id: 42, day: 42, title: "Ask for Advice", description: "Ask someone for advice about a real situation you're facing. Treat the response seriously. (~1–3m)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Asking for advice flips the power dynamic — it positions you as someone who values growth, and people respect that." },
  { id: 43, day: 43, title: "Name the Discomfort", description: "If something feels uncomfortable, say 'That made me uncomfortable' and state it plainly. (~10–30s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Naming discomfort in the moment is a boundary skill — it stops resentment from building and teaches others how to treat you." },
  { id: 44, day: 44, title: "Request Honest Feedback", description: "Ask someone how you come across and request blunt honesty. Prep: choose a trusted person. (~1–3m)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Inviting honest feedback voluntarily transforms fear of judgment into a growth opportunity — you're driving the conversation." },
  { id: 45, day: 45, title: "Cold Approach", description: "Start a short conversation with someone you've never spoken to—no situational excuse required. (~30–90s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Initiating without a 'reason' proves that your desire to connect is reason enough — you don't need a script to be worthy of interaction." },
  { id: 46, day: 46, title: "Small Group Speaking", description: "Speak for ~45 seconds to a group of three or more—share something real and brief. (~45s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Group attention is the ultimate exposure — succeeding here dramatically shrinks the fear response in one-on-one settings." },
  { id: 47, day: 47, title: "Stand with Disapproval", description: "When someone disapproves, acknowledge it and don't apologize. Hold your position calmly. (~10–30s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Surviving disapproval without crumbling rewires the brain's threat response — disapproval is just information, not destruction." },
  { id: 48, day: 48, title: "Awkward Question", description: "Ask a genuinely curious question that may feel slightly awkward. Prep: pick a respectful phrasing. (~10–60s)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Awkward questions often lead to the most meaningful conversations — comfort is overrated; curiosity builds real bonds." },
  { id: 49, day: 49, title: "Selective Apology", description: "Go one day only apologizing when you actually caused harm. Notice urges to say sorry otherwise. (All day)", difficulty: "hard", xpReward: 110, category: "risk", proTip: "Over-apologizing trains the brain that you're always wrong — breaking this pattern restores a balanced sense of responsibility." },
  { id: 50, day: 50, title: "Messy Ending", description: "End a conversation without smoothing things over—leave it imperfect and move on. (~instant)", difficulty: "hard", xpReward: 150, category: "risk", proTip: "Imperfect endings are normal — tolerating them breaks the compulsion to manage everyone's emotional experience of you." },
  { id: 51, day: 51, title: "Express Care", description: "Tell someone, using their name, why you appreciate them. Be specific and direct. (~30–60s)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Expressing appreciation deepens bonds and shifts focus from self-monitoring to valuing others — the ultimate anxiety antidote." },
  { id: 52, day: 52, title: "Own Your Mistake", description: "Admit a real mistake, state what you learned, and stop—no over-explaining. (~30–60s)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Cleanly owning mistakes earns more respect than defensiveness ever could — accountability is magnetic." },
  { id: 53, day: 53, title: "Ask for Support", description: "Tell someone you need help and be specific about what would help. (~30–90s)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Asking for support gives others permission to be vulnerable too — interdependence strengthens relationships far more than independence." },
  { id: 54, day: 54, title: "Share a Fear", description: "Share a genuine fear with someone you trust. Don't minimize it—be honest. (~1–3m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Sharing fears with trusted people transforms them from isolating secrets into shared burdens — connection is the antidote to shame." },
  { id: 55, day: 55, title: "Address Old Hurt", description: "Calmly tell someone about a past hurt. Use 'I' language and avoid blaming. (~1–5m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Addressing old hurts with 'I' statements closes emotional loops — unspoken pain festers; spoken pain can heal." },
  { id: 56, day: 56, title: "Bold Ask", description: "Ask for something meaningful you want and accept that you may hear 'no'. (~1–5m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Making bold asks rewires the scarcity mindset — asking costs nothing, and 'no' is just information, not a verdict on your worth." },
  { id: 57, day: 57, title: "Allow Disagreement", description: "Let someone disagree with you fully. Don't try to change their mind—observe and respond calmly. (~instant–2m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Allowing disagreement without engaging proves that your self-worth isn't tied to being right — it's anchored internally." },
  { id: 58, day: 58, title: "Unguarded Conversation", description: "Have one conversation where you don't try to manage the other person's feelings—speak honestly and listen. (~5–15m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Dropping emotional management frees both people — authentic conversation is lighter and more connecting than controlled performance." },
  { id: 59, day: 59, title: "Authority Conversation", description: "Have a real conversation with someone whose opinion matters to you (boss, mentor, parent). (~5–15m)", difficulty: "hard", xpReward: 120, category: "integration", proTip: "Speaking authentically with authority figures proves you can hold your own — status gaps don't diminish your value." },
  { id: 60, day: 60, title: "Face Your Ghost", description: "Do the social action you've avoided for months. If this feels too big, choose a smaller meaningful step and celebrate it. (~varies)", difficulty: "hard", xpReward: 150, category: "integration", proTip: "Facing your biggest avoidance is the capstone of exposure therapy — you've built the skills; now claim the freedom you've earned." },
];

// Public Speaking Path - 60 Days
const publicSpeakingChallenges: RawChallenge[] = [
  { id: 101, day: 1, title: "Breath & Sound", description: "Stand and speak for 60 seconds, focusing on steady breathing between sentences. Keep it simple—one idea. (1m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Breath control anchors your nervous system — a steady voice starts with steady breathing, not confidence." },
  { id: 102, day: 2, title: "Record & Review", description: "Record one paragraph read aloud. Listen back and note one clear improvement to work on. (~2–4m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Self-review builds objective awareness — hearing yourself removes the gap between how you think you sound and reality." },
  { id: 103, day: 3, title: "Deliberate Pace", description: "Read a short paragraph at half your normal speed. Enunciate every word. (~1–2m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Slowing down signals authority — rushed speech is often a subconscious attempt to get through discomfort quickly." },
  { id: 104, day: 4, title: "Eliminate Fillers", description: "Speak for 90 seconds, pausing instead of saying 'um', 'uh', or 'like'. Practice silent pauses. (1.5m)", difficulty: "medium", xpReward: 60, category: "vocal", proTip: "Silent pauses read as thoughtfulness; filler words read as uncertainty — the same gap, completely different impression." },
  { id: 105, day: 5, title: "Project Across Room", description: "Project your voice as if addressing someone 15 feet away. Maintain that volume for two minutes. (2m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Physical projection engages your diaphragm — it literally changes your body's stress response by activating deeper breathing." },
  { id: 106, day: 6, title: "Sentence Endings", description: "Speak ten sentences and make each ending sound intentional—finish strongly. (~1–2m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Strong endings signal conviction — trailing off at the end of sentences undermines everything you just said." },
  { id: 107, day: 7, title: "Tactical Pause", description: "Before answering questions today, pause for three seconds. Make the pause purposeful. (~3s each)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "The pre-answer pause is a power move — it communicates that you're considering, not scrambling." },
  { id: 108, day: 8, title: "Standing Delivery", description: "Stand and speak for three minutes. Notice breath and how your posture affects tone. (3m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Standing opens your airway and projects confidence — your physical stance directly shapes your vocal presence." },
  { id: 109, day: 9, title: "Monotone Baseline", description: "Speak in a flat tone for 90 seconds, then repeat with added emotion—compare the difference. (1.5m)", difficulty: "easy", xpReward: 50, category: "vocal", proTip: "Contrast reveals range — feeling the difference between flat and expressive speech builds conscious control over your vocal instrument." },
  { id: 110, day: 10, title: "Clean Recording", description: "Record yourself reading one page. Re-record until filler words are minimal—aim for progress, not perfection. (~5–10m)", difficulty: "medium", xpReward: 150, category: "vocal", proTip: "Iterative recording is deliberate practice — each retake builds neural pathways for cleaner speech that eventually becomes automatic." },
  { id: 111, day: 11, title: "Single Point", description: "Explain one idea in exactly one sentence with no qualifiers—clear and direct. (~10–20s)", difficulty: "easy", xpReward: 60, category: "structure", proTip: "Single-sentence clarity forces prioritization — if you can't say it in one sentence, you don't understand it yet." },
  { id: 112, day: 12, title: "30-Second Summary", description: "Summarize a topic you know in exactly 30 seconds—time it and be concise. (30s)", difficulty: "medium", xpReward: 70, category: "structure", proTip: "Time-boxing builds discipline — audiences value speakers who respect their time over those who fill it." },
  { id: 113, day: 13, title: "Explain to a Child", description: "Explain a complex idea as if to a 10-year-old. Record it to check clarity. (~2–4m)", difficulty: "easy", xpReward: 60, category: "structure", proTip: "If you can't explain it simply, you don't truly know it — this exercise sharpens both understanding and delivery." },
  { id: 114, day: 14, title: "Concrete Example", description: "Make a point and give one specific example—stop there. Practice brevity. (~30–60s)", difficulty: "easy", xpReward: 60, category: "structure", proTip: "One clear example beats three vague ones — specificity is the engine of memorable communication." },
  { id: 115, day: 15, title: "Rephrase It", description: "Say one idea, then rephrase it with completely different words—same meaning, new phrasing. (~30–60s)", difficulty: "medium", xpReward: 70, category: "structure", proTip: "Rephrasing on the fly builds cognitive flexibility — you'll never be trapped when your first wording doesn't land." },
  { id: 116, day: 16, title: "Bookend Structure", description: "Open with 'I'm going to explain X' and close with 'That's X'—fill the middle clearly. (~1–2m)", difficulty: "easy", xpReward: 60, category: "structure", proTip: "Bookending gives your audience a mental container — they retain more when they know where you're going and when you've arrived." },
  { id: 117, day: 17, title: "Because Why", description: "Make a claim and answer 'why' three times, going deeper each time. Keep responses concise. (~1–2m)", difficulty: "medium", xpReward: 70, category: "structure", proTip: "The 'five whys' technique uncovers root causes — each layer of 'why' adds intellectual depth that audiences find compelling." },
  { id: 118, day: 18, title: "Three-Part Talk", description: "Deliver a three-minute talk with a clear intro, body, and conclusion. Time yourself. (3m)", difficulty: "medium", xpReward: 70, category: "structure", proTip: "The three-part structure is psychologically satisfying — audiences are conditioned to process beginning-middle-end narratives effortlessly." },
  { id: 119, day: 19, title: "Cut the Fat", description: "Write 100 words about a topic, then cut it to 50 while keeping the main idea intact. (~10–20m)", difficulty: "medium", xpReward: 70, category: "structure", proTip: "Editing yourself ruthlessly trains economy of language — every word you cut makes the remaining ones more powerful." },
  { id: 120, day: 20, title: "Topic Discipline", description: "Speak for four minutes on one topic—each time you drift, bring it back. (4m)", difficulty: "medium", xpReward: 150, category: "structure", proTip: "Staying on topic is harder than it seems — this builds the mental discipline that separates polished speakers from ramblers." },
  { id: 121, day: 21, title: "No Notes", description: "Speak for two minutes on a familiar topic with zero notes—rely on structure. (2m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Ditching notes builds true mastery — when you know your structure, you can focus entirely on connection instead of recollection." },
  { id: 122, day: 22, title: "Sustained Eye Contact", description: "Speak for one minute while holding eye contact with a single person or the camera. (1m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Eye contact releases oxytocin — sustained gaze builds trust and makes your words feel personally addressed to each listener." },
  { id: 123, day: 23, title: "Purposeful Gesture", description: "Use three deliberate gestures during a 90-second talk—each gesture should underscore a point. (1.5m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Gesture anchors memory — audiences remember points paired with physical movement significantly better than words alone." },
  { id: 124, day: 24, title: "Pace Mastery", description: "Speak for two minutes and intentionally vary pace for emphasis and clarity. (2m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Varied pace creates rhythm — monotone speed puts audiences to sleep; dynamic pacing keeps them leaning forward." },
  { id: 125, day: 25, title: "Calm Through Nerves", description: "Notice nervous feelings while speaking and maintain steady pace—acknowledge the nerves but continue. (~1–3m)", difficulty: "hard", xpReward: 90, category: "delivery", proTip: "Nerves and performance can coexist — the goal isn't to eliminate anxiety, it's to function effectively alongside it." },
  { id: 126, day: 26, title: "Critical Review", description: "Record a three-minute talk, watch it, and list three specific improvements without harsh self-criticism. (~10–20m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Objective self-critique without self-attack is a meta-skill — it separates your identity from your performance." },
  { id: 127, day: 27, title: "Emotional Range", description: "Deliver a two-minute piece with one neutral segment, one energized segment, and one serious segment. (2m)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "Emotional variety keeps audiences engaged — the contrast between tones creates a journey, not a lecture." },
  { id: 128, day: 28, title: "Decisive Ending", description: "End a short talk with one strong closing sentence. No trailing qualifiers. (~5–10s)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "The last thing you say echoes longest — a weak ending can undo a strong talk; a strong ending can rescue a shaky one." },
  { id: 129, day: 29, title: "Hook Opening", description: "Open with a bold hook (question, surprising fact, or statement) that grabs attention in five seconds. (~5s)", difficulty: "medium", xpReward: 80, category: "delivery", proTip: "You have about seven seconds to earn attention — a strong hook exploits the brain's novelty-seeking circuitry." },
  { id: 130, day: 30, title: "Zero Self-Critique", description: "Speak for four minutes and resist self-criticism or disclaimers—record and celebrate completion. (4m)", difficulty: "hard", xpReward: 150, category: "delivery", proTip: "Self-criticism during delivery splits your attention — speaking freely without the inner judge produces your most natural, compelling performance." },
  { id: 131, day: 31, title: "Random Topic", description: "Pick a random word and speak about it for 90 seconds with no prep—focus on structure and flow. (1.5m)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Impromptu speaking builds neural agility — the brain gets faster at organizing thoughts when it practices without a safety net." },
  { id: 132, day: 32, title: "Instant Response", description: "Answer a spontaneously asked question immediately—avoid filler pauses and stay concise. (~10–60s)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Trusting your first thought builds confidence in your instincts — your unfiltered response is usually better than you think." },
  { id: 133, day: 33, title: "Teach Back", description: "Learn a quick concept in five minutes and teach it back clearly in your own words. (~5m learn + 1–2m teach)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Teaching cements learning — the act of rephrasing for others forces deep processing that passive consumption never achieves." },
  { id: 134, day: 34, title: "Zero Prep Talk", description: "Start a two-minute talk on any topic right now—no planning. Keep the structure tight. (2m)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "The blank-page start is the hardest — mastering it proves you can speak on anything, anytime, anywhere." },
  { id: 135, day: 35, title: "Smooth Recovery", description: "Speak for three minutes and practice pausing two seconds when you lose your place, then continue. (3m)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Recovery grace is more impressive than perfection — audiences forgive mistakes; they don't forgive panic." },
  { id: 136, day: 36, title: "Mid-Thought Pause", description: "Stop mid-sentence, pause three seconds, and resume exactly where you left off—practice once. (~10–30s)", difficulty: "medium", xpReward: 85, category: "improvisation", proTip: "Owning a mid-sentence pause turns awkward silence into dramatic effect — the audience waits because you're in control." },
  { id: 137, day: 37, title: "Handle Interruption", description: "Have someone interrupt you while speaking—acknowledge them briefly, then return to your point smoothly. (~30–60s)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Graceful interruption handling signals unshakeable composure — you acknowledge others without ceding your platform." },
  { id: 138, day: 38, title: "Instant Summary", description: "Immediately summarize a recent conversation in 60 seconds—focus on clarity and key points. (1m)", difficulty: "medium", xpReward: 85, category: "improvisation", proTip: "Summarizing on demand trains your brain to filter signal from noise — the essence of impactful communication." },
  { id: 139, day: 39, title: "Distracted Speaking", description: "Speak for three minutes while noise or movement occurs—maintain focus and presence. (3m)", difficulty: "hard", xpReward: 100, category: "improvisation", proTip: "Real-world speaking has distractions — building immunity to environmental noise makes you unshakable in any venue." },
  { id: 140, day: 40, title: "Unknown & Continue", description: "If asked something you don't know, state that plainly and pivot to what you do know—practice the pivot once. (~20–40s)", difficulty: "hard", xpReward: 150, category: "improvisation", proTip: "The 'honest pivot' is more credible than bluffing — audiences trust speakers who admit knowledge boundaries and redirect confidently." },
  { id: 141, day: 41, title: "Single Audience", description: "Deliver a three-minute talk to one attentive person who will give feedback—treat them as a real audience. (3m)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "One engaged listener is a real audience — learning to speak to one person well scales naturally to larger groups." },
  { id: 142, day: 42, title: "Apply Critique", description: "Collect one concrete piece of feedback and implement that exact change in your next short talk. (~3–10m)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Applying one piece of feedback at a time prevents overwhelm — incremental improvement compounds faster than trying to fix everything." },
  { id: 143, day: 43, title: "Public Recording", description: "Share a recording with three people and ask each for one specific improvement. Review answers without defensiveness. (~5–15m)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Multiple perspectives reveal blind spots — patterns in feedback are more valuable than any single opinion." },
  { id: 144, day: 44, title: "Observed Speaking", description: "Speak for three minutes while someone evaluates you—don't change delivery mid-talk. (3m)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Performing under observation without adapting to the observer builds authenticity — you're training to be yourself under scrutiny." },
  { id: 145, day: 45, title: "Tough Question", description: "Answer a critical question for 60 seconds—stay concise and composed. (~1m)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Critical questions test composure, not knowledge — staying calm under fire is more persuasive than having the perfect answer." },
  { id: 146, day: 46, title: "Defend Without Defense", description: "When challenged, restate your point calmly without getting defensive—use two clear sentences. (~30–60s)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Defensiveness signals weakness; calm restatement signals strength — the same content, delivered differently, changes everything." },
  { id: 147, day: 47, title: "Small Group Presentation", description: "Present for four minutes to a small group (4–6 people). Make brief eye contact with several listeners. (4m)", difficulty: "hard", xpReward: 120, category: "feedback", proTip: "Distributing eye contact across a group makes everyone feel included — each person feels you're speaking to them individually." },
  { id: 148, day: 48, title: "Live Q&A", description: "Give a short talk (2 minutes) and then take questions for three minutes—answer succinctly. (5m)", difficulty: "hard", xpReward: 120, category: "feedback", proTip: "Q&A is where credibility is built — a talk earns attention; your answers earn trust." },
  { id: 149, day: 49, title: "Mistake & Move", description: "Make an intentional or accidental error while speaking, acknowledge it in five words or less, and continue. (~instant)", difficulty: "hard", xpReward: 110, category: "feedback", proTip: "Quick error acknowledgment and continuation models resilience — the audience follows your lead: if you're fine, they're fine." },
  { id: 150, day: 50, title: "Complete Follow-Through", description: "Deliver a full short talk start-to-finish without restarting or apologizing—finish cleanly. (~4–6m)", difficulty: "hard", xpReward: 150, category: "feedback", proTip: "Finishing without self-sabotage is a milestone — the urge to restart or apologize is the last vestige of perfectionism." },
  { id: 151, day: 51, title: "Structured Presentation", description: "Deliver a five-minute talk with a clear structure on something you're passionate about—time yourself. (5m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Passion is the best delivery aid — when you care deeply about a topic, structure becomes intuitive and presence becomes natural." },
  { id: 152, day: 52, title: "Medium Crowd", description: "Speak to 10–15 people for five minutes. Treat it like a conversation—engage a few listeners. (5m)", difficulty: "hard", xpReward: 130, category: "performance", proTip: "Treating a crowd as a conversation lowers the stakes — you're just talking to people, not performing for an audience." },
  { id: 153, day: 53, title: "Extended Q&A", description: "Present for three minutes, then field questions for seven minutes—stay composed and concise. (10m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Longer Q&A sessions build endurance — staying sharp over time is what separates good speakers from great ones." },
  { id: 154, day: 54, title: "Noteless Delivery", description: "Give a complete six-minute talk with zero notes or prompts—rely on practiced structure. (6m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Noteless delivery frees you to connect — when you're not referencing notes, you're fully present with your audience." },
  { id: 155, day: 55, title: "Nervous & Steady", description: "Feel the nerves fully but deliver with steady pace and volume—document one thing you handled well. (~5–10m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Nerves don't prevent great delivery — acknowledging what went well rewires your brain to associate nerves with success, not failure." },
  { id: 156, day: 56, title: "Story Integration", description: "Integrate one short personal story into a technical talk—make it relevant and concise. (~3–6m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Stories are the oldest form of communication — a well-placed personal anecdote makes data memorable and humanizes the speaker." },
  { id: 157, day: 57, title: "Record, Review, Redo", description: "Record a five-minute talk, review to identify two improvements, then re-record applying them. (~15–30m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Iterative recording with specific targets is deliberate practice — you improve faster by focusing on two things than by vaguely 'trying harder.'" },
  { id: 158, day: 58, title: "New Environment", description: "Deliver a talk in an unfamiliar place (park, café, office). Note how environment changes delivery. (~5–15m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Adapting to novel environments builds true mastery — you're not a 'conference room speaker,' you're a speaker, period." },
  { id: 159, day: 59, title: "Multiple Feedback Sources", description: "Present to three or more people and collect written feedback from each—review without defensiveness. (~10–30m)", difficulty: "hard", xpReward: 120, category: "performance", proTip: "Written feedback removes emotional reactions — read it once, sit with it, then extract the useful patterns." },
  { id: 160, day: 60, title: "Public Talk", description: "Deliver a ten-minute talk to a real audience (15+ people). Own the room—plan, rehearse, and execute. (~10m+)", difficulty: "hard", xpReward: 150, category: "performance", proTip: "The capstone: everything you've practiced converges here. Trust your preparation — the audience wants you to succeed." },
];

// Assertiveness Path - 60 Days
const assertivenessChallenges: RawChallenge[] = [
  { id: 201, day: 1, title: "Direct Preference", description: "When asked, state what you want in five words or fewer. Avoid 'I don't care' or 'whatever.' (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Stating preferences concisely builds self-trust — the first step to assertiveness is knowing what you actually want." },
  { id: 202, day: 2, title: "Choose First", description: "Make a choice without consulting others first—decide and state it clearly. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Choosing without external validation trains independence — your judgment is sufficient; it doesn't need a committee." },
  { id: 203, day: 3, title: "Say 'I Want'", description: "Use the phrase 'I want' once today to state a simple desire—say it plainly. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "'I want' is a complete sentence — using it directly challenges the belief that desires need justification to be valid." },
  { id: 204, day: 4, title: "No Justification", description: "Make a small decision and, if asked why, reply 'Because I prefer it.' Stop there. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "You don't owe anyone a dissertation on your preferences — 'because I prefer it' is a complete and legitimate answer." },
  { id: 205, day: 5, title: "Unapologetic Choice", description: "Choose something for yourself without prefacing it with 'sorry' or 'if that's okay.' (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Prefacing choices with apologies trains others to question your decisions — unapologetic choice signals self-respect." },
  { id: 206, day: 6, title: "State and Stop", description: "Speak a decision aloud and don't explain or ask for validation—hold the statement. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Holding a statement without seeking nods or agreement is uncomfortable at first — it's also the foundation of self-trust." },
  { id: 207, day: 7, title: "Clear 'I Want' Statement", description: "Say 'I want X' in one sentence with no qualifiers—practice once if helpful. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Qualifiers dilute desire — every 'maybe' or 'kind of' you remove makes your statement stronger and more likely to be respected." },
  { id: 208, day: 8, title: "Fewer Words", description: "Express a preference using fewer than five words—no elaboration. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Brevity is a power move — the fewer words you use, the more each one weighs." },
  { id: 209, day: 9, title: "Lead the Choice", description: "Be the first to pick in a group decision—state your choice confidently. (~5–10s)", difficulty: "easy", xpReward: 50, category: "clarity", proTip: "Going first in group decisions breaks the habit of anchoring to others — your preferences can set the frame, not just fit inside it." },
  { id: 210, day: 10, title: "Opinion as Statement", description: "State an opinion as a simple fact—avoid qualifiers like 'I think' or 'maybe.' (~5–10s)", difficulty: "easy", xpReward: 150, category: "clarity", proTip: "Stating opinions as facts projects conviction — 'this movie is great' lands differently than 'I think this movie is kind of good.'" },
  { id: 211, day: 11, title: "Simple No", description: "Say 'no' to a small request once today—do not explain or apologize. (~5–10s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "'No' is a complete sentence — every explanation you add is an invitation to negotiate your boundary." },
  { id: 212, day: 12, title: "Delay Response", description: "When asked for something, say 'Let me think about it' instead of giving an immediate yes. (~5–10s)", difficulty: "easy", xpReward: 60, category: "boundaries", proTip: "Buying time breaks the auto-yes reflex — pausing gives your authentic self a chance to weigh in before people-pleasing takes over." },
  { id: 213, day: 13, title: "Decline Invitation", description: "Turn down an invitation politely in one sentence—no long excuses. (~5–10s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "Declining without over-explaining communicates that your time is valuable — long excuses suggest you need permission to say no." },
  { id: 214, day: 14, title: "Correct Without Sorry", description: "Correct someone gently but do not apologize for correcting them. Keep tone neutral. (~10–20s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "Apologizing before correcting undermines your accuracy — being right doesn't require contrition." },
  { id: 215, day: 15, title: "Clear 'I Can't'", description: "Say 'I can't do that' plainly when you can't—avoid adding softeners. (~5–10s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "A clean 'I can't' is stronger than a softened 'I'm not sure I can' — clarity protects your boundaries without being aggressive." },
  { id: 216, day: 16, title: "Time Limit", description: "Set a specific time limit for a meeting or chat and enforce it when time's up. (~duration)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "Enforcing time limits trains others to respect your schedule — and trains you to believe your time is worth protecting." },
  { id: 217, day: 17, title: "Push Back Once", description: "When offered a suggestion, say 'I'd prefer not to' and give one short reason at most. (~10–20s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "Pushing back once without escalating proves you can disagree without conflict — most people accept a single, calm refusal." },
  { id: 218, day: 18, title: "Ask for Time", description: "Ask for time to think before committing—use a calm phrase like 'Let me get back to you.' (~5–10s)", difficulty: "easy", xpReward: 60, category: "boundaries", proTip: "Asking for time before committing is a right, not a favor — you're protecting your future self from impulsive yeses." },
  { id: 219, day: 19, title: "That Doesn't Work", description: "Say 'That doesn't work for me' and offer one alternative. Keep it simple. (~10–20s)", difficulty: "medium", xpReward: 70, category: "boundaries", proTip: "Pairing a refusal with an alternative shifts you from 'difficult' to 'solution-oriented' — same boundary, better reception." },
  { id: 220, day: 20, title: "Hold Without Explaining", description: "Set a boundary and, if questioned, respond 'That's my decision.' Do not justify. (~5–10s)", difficulty: "hard", xpReward: 150, category: "boundaries", proTip: "Refusing to justify your boundary is the ultimate assertion of autonomy — you are the authority on your own limits." },
  { id: 221, day: 21, title: "Repeat No", description: "Say 'no.' If pressured, repeat the same exact 'no' without changing or adding reasons. (~5–20s)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "The 'broken record' technique is psychologically sound — people push boundaries to test them; consistency proves they're real." },
  { id: 222, day: 22, title: "Ignore Guilt", description: "If someone tries to guilt you into changing your boundary, notice it and do not back down. (~instant)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "Guilt-tripping is a manipulation tactic, not a valid argument — recognizing it as such disarms its emotional power." },
  { id: 223, day: 23, title: "End Discussion", description: "State your boundary clearly. If debate continues, say 'I've made my decision' and end the talk. (~10–30s)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "Ending the discussion is a boundary itself — you're not obligated to debate decisions that affect your own wellbeing." },
  { id: 224, day: 24, title: "Second No", description: "If your first 'no' is ignored, repeat it once more and hold firm. (~5–20s)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "The second no is often the real test — many people ignore the first one by default; the second one establishes that you mean it." },
  { id: 225, day: 25, title: "Calm and Firm", description: "Assert a boundary with a neutral, steady voice—practice the tone once before you use it. (~10–30s)", difficulty: "medium", xpReward: 80, category: "enforcement", proTip: "Neutral tone removes emotional charge — calm firmness is more persuasive than anger and more respected than pleading." },
  { id: 226, day: 26, title: "Uncomfortable and Firm", description: "Maintain a boundary even while feeling uncomfortable—notice the feeling but keep the boundary. (~instant–1m)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "Discomfort during boundary-setting is normal — it's the feeling of growth, not a signal that you're doing something wrong." },
  { id: 227, day: 27, title: "Friend Boundary", description: "Enforce a clear boundary with a friend—be kind but firm; plan one sentence to say. (~30–60s)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "Boundaries with friends are harder but more important — real friendship survives limits; fake friendship resents them." },
  { id: 228, day: 28, title: "Protect Your Energy", description: "Say no to something that benefits others but drains you—prioritize your limits. (~instant)", difficulty: "hard", xpReward: 90, category: "enforcement", proTip: "Protecting your energy isn't selfish — you can't pour from an empty cup, and boundaries ensure you have something left to give." },
  { id: 229, day: 29, title: "Ask for Need", description: "Tell someone in one direct sentence what you need right now. Keep it clear and factual. (~10–20s)", difficulty: "medium", xpReward: 80, category: "enforcement", proTip: "Directly stating needs is vulnerability plus strength — people can't meet needs they don't know about." },
  { id: 230, day: 30, title: "Stop Accommodating", description: "Catch moments when you are about to accommodate at your expense and choose not to. (All day)", difficulty: "hard", xpReward: 150, category: "enforcement", proTip: "Accommodation at self-expense is a learned pattern — catching it in real-time is the first step to breaking it permanently." },
  { id: 231, day: 31, title: "Respectful Disagree", description: "Say 'I disagree' and state your view in two clear sentences without apologizing. (~20–40s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Disagreeing respectfully models healthy conflict — most people fear disagreement because they've only experienced it as attack, not dialogue." },
  { id: 232, day: 32, title: "Different Perspective", description: "Say 'I see it differently' and explain your view concisely—don't seek approval after. (~20–40s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Your perspective doesn't need validation — stating it without scanning for approval builds internal validation." },
  { id: 233, day: 33, title: "Offer Alternative", description: "When disagreeing with a plan, offer a single concrete alternative solution. (~20–40s)", difficulty: "medium", xpReward: 90, category: "disagreement", proTip: "Disagreement + solution = leadership — people resist 'no' but welcome 'how about this instead.'" },
  { id: 234, day: 34, title: "Hold Your Ground", description: "State your position and, if challenged, calmly restate it without escalating into argument. (~20–60s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Calm restatement under pressure is a superpower — you control the emotional temperature, not the person challenging you." },
  { id: 235, day: 35, title: "Eye Contact in Conflict", description: "Keep steady, calm eye contact while expressing a disagreement. Breathe and stay grounded. (~10–30s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Steady eye contact during disagreement projects inner calm — it signals that conflict doesn't threaten your sense of safety." },
  { id: 236, day: 36, title: "Repeat if Dismissed", description: "If your point is dismissed, say 'I want to restate this' and repeat it once with the same wording. (~10–30s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Being dismissed doesn't make your point invalid — restating calmly reclaims your voice without escalating." },
  { id: 237, day: 37, title: "Allow Tension", description: "Let tension exist after a disagreement without smoothing it over—observe and stay present. (~instant–2m)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Tension after disagreement is natural — rushing to smooth it over teaches people that your boundaries are negotiable." },
  { id: 238, day: 38, title: "No Approval Seeking", description: "Disagree and notice any urge to seek approval—resist it and stand by your words. (~instant)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "The urge to seek approval after disagreeing is a habit, not a need — resisting it rewires your validation source from external to internal." },
  { id: 239, day: 39, title: "Stay Composed", description: "Maintain calm body language and tone while someone pressures you—practice a steady phrase to use. (~10–60s)", difficulty: "hard", xpReward: 100, category: "disagreement", proTip: "Composure under pressure is a physical skill — your body staying calm signals your brain that you're safe, which keeps your mind clear." },
  { id: 240, day: 40, title: "Defend Your Idea", description: "Respond to criticism of your idea with two to three clear supporting points—stay factual and concise. (~30–90s)", difficulty: "hard", xpReward: 150, category: "disagreement", proTip: "Defending ideas with facts, not emotion, commands respect — you're advocating for the idea, not protecting your ego." },
  { id: 241, day: 41, title: "Ask Directly", description: "Ask for something you want and accept the possibility of 'no'—be direct and succinct. (~30–90s)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Asking directly with acceptance of 'no' is the pinnacle of assertive communication — you advocate without demanding." },
  { id: 242, day: 42, title: "Request Raise", description: "Request a raise, promotion, or improvement. Prepare three concise reasons and present them confidently. (~5–20m)", difficulty: "hard", xpReward: 120, category: "advocacy", proTip: "Advocating for your worth professionally is self-respect in action — the worst outcome is 'no,' which leaves you exactly where you started." },
  { id: 243, day: 43, title: "Request Behavior Change", description: "Ask someone to change a specific behavior that affects you. Be clear about the behavior and the desired change. (~1–5m)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Requesting behavior change is relationship care, not criticism — unaddressed issues fester; addressed ones can heal." },
  { id: 244, day: 44, title: "Speak to Authority", description: "Have a direct, clear conversation with someone in authority about a need or issue. (~5–20m)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Authority figures are just people — speaking to them directly dismantles the hierarchy illusion that silences you." },
  { id: 245, day: 45, title: "Honest Feedback", description: "Give a peer honest, specific, and kind critical feedback—focus on observable behavior and outcome. (~5–15m)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Honest feedback given kindly is a gift — most people never receive it, and those who do grow faster because of it." },
  { id: 246, day: 46, title: "Close Person Boundary", description: "Set a clear boundary with someone close to you. Use one short sentence to state it and your need. (~5–15m)", difficulty: "hard", xpReward: 120, category: "advocacy", proTip: "Boundaries with loved ones are the hardest and most important — closeness without boundaries is enmeshment, not intimacy." },
  { id: 247, day: 47, title: "Ask for Help Directly", description: "Say 'I need help with X' without apologizing—state exactly what you need. (~10–60s)", difficulty: "medium", xpReward: 100, category: "advocacy", proTip: "Asking for help without apology is strength — it communicates that your needs are legitimate, not burdensome." },
  { id: 248, day: 48, title: "Accept No Calmly", description: "When you hear 'no', respond 'okay' and move on without pleading. Practice once beforehand. (~5–10s)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Gracefully accepting 'no' closes the loop — it models the very respect for boundaries that you're asking others to show you." },
  { id: 249, day: 49, title: "Follow-Up Request", description: "If initially denied, bring the request up again later with new reasoning—stay concise and factual. (~1–5m)", difficulty: "hard", xpReward: 110, category: "advocacy", proTip: "Persistence without pressure is advocacy — a well-timed follow-up with new information is persistence, not nagging." },
  { id: 250, day: 50, title: "Stand Through Criticism", description: "Maintain your position calmly when criticized—avoid over-explaining or folding. (~1–5m)", difficulty: "hard", xpReward: 150, category: "advocacy", proTip: "Standing through criticism without crumbling proves your position is conviction, not convenience — it's the ultimate test of assertiveness." },
  { id: 251, day: 51, title: "Unfiltered Truth", description: "Say exactly what you mean without softening it for others' comfort—choose a safe person or context. (~30–90s)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Unfiltered truth with safe people builds authentic relationships — the people who can handle your honesty are your real community." },
  { id: 252, day: 52, title: "Stand in Conflict", description: "Stay present in a conflict until resolution—don't leave early to avoid discomfort. (~varies)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Staying through conflict resolution rewires your flight response — conflicts that get resolved build stronger relationships than conflicts avoided." },
  { id: 253, day: 53, title: "Request Commitment", description: "Ask someone for a specific commitment with a deadline; follow up if it's missed. (~5–15m)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Holding others accountable is self-respect — your needs deserve follow-through, and asking for it models the standard you expect." },
  { id: 254, day: 54, title: "Boundary Under Pressure", description: "Hold a boundary even when several people pressure you to change it—plan a short, firm response. (~instant–5m)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Group pressure is the hardest boundary test — holding firm against multiple people proves your limits are non-negotiable." },
  { id: 255, day: 55, title: "Direct Feedback", description: "Give critical feedback without sugarcoating—be constructive, specific, and brief. (~5–15m)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Unsugarcoated feedback respects the recipient's intelligence — clarity is kindness; ambiguity is avoidance." },
  { id: 256, day: 56, title: "Admit & Reset", description: "Admit when you are wrong, then set a new, clear boundary—keep both parts concise. (~30–90s)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Admitting fault and resetting boundaries in one motion is emotional maturity — you can be imperfect and still deserve limits." },
  { id: 257, day: 57, title: "Relationship Ask", description: "Ask for what you need in a relationship—be specific about the change and your request. (~5–15m)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Unspoken needs become resentment — asking directly gives relationships a chance to meet you rather than fail you silently." },
  { id: 258, day: 58, title: "Enforce Consequence", description: "When a boundary is crossed, follow through on the consequence you stated—do it calmly and promptly. (~instant–varies)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "Empty consequences teach people your boundaries are optional — following through, even once, teaches them you're serious." },
  { id: 259, day: 59, title: "High-Pressure Stance", description: "Maintain your assertiveness during a high-pressure situation (meeting, negotiation). (~varies)", difficulty: "hard", xpReward: 120, category: "autonomy", proTip: "High-pressure assertiveness is the final exam — if you can stay firm when the stakes are high, you've truly internalized the skill." },
  { id: 260, day: 60, title: "Bold Life Decision", description: "Make one significant decision that prioritizes your needs over expectations. If this feels too big, choose a smaller meaningful step and celebrate it. (~varies)", difficulty: "hard", xpReward: 150, category: "autonomy", proTip: "This is your life — making decisions that honor your needs over others' expectations is the ultimate expression of assertiveness." },
];

const addPath = (challenges: RawChallenge[], path: PathType): Challenge[] =>
  challenges.map((c) => ({ ...c, path }));

export const getChallengesForPath = (path: PathType): Challenge[] => {
  switch (path) {
    case "introvert":
      return addPath(socialAnxietyChallenges, "introvert");
    case "speaking":
      return addPath(publicSpeakingChallenges, "speaking");
    case "assertiveness":
      return addPath(assertivenessChallenges, "assertiveness");
    default:
      return addPath(socialAnxietyChallenges, "introvert");
  }
};
